+                arr.deinit(allocator);
+            },
+            .object => |*obj| {
+                var it = obj.iterator();
+                while (it.next()) |entry| {
+                    allocator.free(entry.key_ptr.*);
+                    entry.value_ptr.deinit(allocator);
+                }
+                obj.deinit();
+            },
+            else => {},
+        }
+    }
