+                }
+            }
+        }
+    }
+
+    // Handle remainder
+    var pos = i;
+    while (pos < data.len) : (pos += 1) {
+        const c = data[pos];
+        if (c != ' ' and c != '\t' and c != '\n' and c != '\r') {
+            return pos;
+        }
+    }
+    return data.len;
+}
