+    pub fn isControl(self: Opcode) bool {
+        return @intFromEnum(self) & 0x8 != 0;
+    }
+};
+
+pub const CloseCode = enum(u16) {
+    Normal = 1000,
+    GoingAway = 1001,
+    ProtocolError = 1002,
+    UnsupportedData = 1003,
+    NoStatus = 1005,
+    Abnormal = 1006,
+    InvalidPayload = 1007,
+    PolicyViolation = 1008,
+    MessageTooBig = 1009,
+    MandatoryExtension = 1010,
+    InternalError = 1011,
+    _,
+};
