+/// Apply XOR mask to payload data
+pub fn applyMask(data: []u8, mask: [4]u8) void {
+    for (data, 0..) |*byte, i| {
+        byte.* ^= mask[i % 4];
+    }
+}
+
+/// Generate random masking key
+pub fn generateMask() [4]u8 {
+    var mask: [4]u8 = undefined;
+    std.crypto.random.bytes(&mask);
+    return mask;
